%Doctor.Config{
  min_module_doc_coverage: 0,
  min_module_spec_coverage: 0,
  min_overall_doc_coverage: 40,
  min_overall_spec_coverage: 0,
  min_overall_moduledoc_coverage: 100,
  struct_type_spec_required: false,
  ignore_modules: [
